"""Small analysis helpers for experiment outputs."""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any


def load_validation_summary(path: str | Path) -> list[dict[str, Any]]:
    """Load a compact validation summary generated by the smoke runner."""
    data = json.loads(Path(path).read_text(encoding="utf-8"))
    if not isinstance(data, list):
        raise ValueError("Validation summary must contain a list of run summaries.")
    return data

